ruleBookInfo.tocUrl:
@js:
time=Math.round(new Date()/1000)
sign=java.md5Encode("com.ruffianhankin.meritreader1"+time+"vhjJVz1St6tK7!8n#B0MqRIuE2Dh7!C#")
headers={"package":"com.ruffianhankin.meritreader","pt":"1","time":String(time),"sign":String(sign)}
option={"headers":headers}
sourceList =JSON.parse(java.ajax("https://book.lansheweb.com/source/"+parseInt(java.getString('$.book_id')/1000)+"/"+java.getString('$.book_id') +".html,"+JSON.stringify(option))).data.sort((a, b) => Date.parse(b.updated_at.replace(/-/g,"/"))-Date.parse(a.updated_at.replace(/-/g,"/")))
"https://catalog.lansheweb.com/"+ sourceList[0].site_path

